#include <stdio.h>

int main() {
    FILE *f = fopen("hello.txt", "r");
    if (f == NULL) {
        fprintf(stderr, "Error: cannot open file\n");
        return 1;
    }
    char buf[256];
    while (fgets(buf, sizeof(buf), f)) {
        printf("%s", buf);
    }
    fclose(f);
    return 0;
}

